// Find the calmest sailing window within an hourly forecast.
// "Calmest" = lowest combined wind + gust, measured as the mean per-hour
// (windSpeed + windGusts) across the window. Earliest window wins ties.
//
// Pure function: no network or closure dependencies, so it is directly unit-testable.
// Returns null when there is not enough data to form a single window.
function computeBestWindow(hourly: any[], windowHours: number, horizonHours: number) {
  // Guard: need a usable array and a positive window size
  if (!Array.isArray(hourly) || windowHours <= 0) return null;

  // Clamp the search horizon to the data we actually have
  const horizon = Math.min(horizonHours, hourly.length);

  // Not enough hours to form even one window
  if (horizon < windowHours) return null;

  // Round helper — keep displayed numbers to 1 decimal place
  const round1 = (n: number) => Math.round(n * 10) / 10;

  // Slide the window across every valid start index and track the lowest score
  let best: any = null;
  for (let start = 0; start <= horizon - windowHours; start++) {
    const slice = hourly.slice(start, start + windowHours);

    // Sum wind and gust across the window's hours
    let windSum = 0;
    let gustSum = 0;
    for (const h of slice) {
      windSum += h.windSpeed ?? 0;
      gustSum += h.windGusts ?? 0;
    }

    // Per-hour averages — friendlier numbers for the reason string
    const avgWind = windSum / windowHours;
    const avgGust = gustSum / windowHours;
    const combinedScore = avgWind + avgGust;

    // Keep the earliest window with the strictly-lowest combined score
    if (best === null || combinedScore < best.combinedScore) {
      best = { start, slice, avgWind, avgGust, combinedScore };
    }
  }

  // Should be unreachable given the guards above, but be defensive
  if (best === null) return null;

  const startHour = best.slice[0];
  const endHour = best.slice[best.slice.length - 1];

  // Extract HH:MM from an ISO-ish "YYYY-MM-DDTHH:MM" time string
  const hhmm = (t: string) => {
    if (typeof t !== 'string') return '';
    const idx = t.indexOf('T');
    return idx >= 0 ? t.slice(idx + 1, idx + 6) : t;
  };

  // Classify average wind speed (knots) into a friendly tier label
  const tierLabel = (kn: number) => {
    if (kn < 4) return 'very light';
    if (kn < 8) return 'light';
    if (kn < 14) return 'moderate';
    if (kn < 21) return 'fresh';
    return 'strong';
  };

  const startTime = hhmm(startHour.time);
  const endTime = hhmm(endHour.time);
  const avgWindR = round1(best.avgWind);
  const avgGustR = round1(best.avgGust);

  // Build the short human-readable reason string
  const reason = `Calmest window ${startTime}–${endTime} — ${tierLabel(best.avgWind)} winds averaging `
    + `${avgWindR} kn, gusts to ${avgGustR} kn`;

  return {
    startIndex: best.start,
    start: best.start,
    end: best.start + windowHours - 1,
    startTime: startHour.time,
    endTime: endHour.time,
    avgWind: avgWindR,
    avgGust: avgGustR,
    combinedScore: round1(best.combinedScore),
    // Trimmed per-hour data for the calmest window
    hours: best.slice.map((h: any) => ({
      time: h.time,
      windSpeed: h.windSpeed,
      windGusts: h.windGusts
    })),
    reason
  };
}
